html:
{% set company = frappe.get_doc('Company', doc.company) if doc.company else None %}
{% set owner_name = frappe.db.get_value('User', doc.owner, 'full_name') or doc.owner or '' %}
{% set _ca_link = doc.company_address or None %}
{% if company and not _ca_link %}
{% set _ca_link = frappe.call('erpnext.setup.doctype.company.company.get_default_company_address', name=company.name) %}
{% endif %}
{% set company_addr = frappe.get_doc('Address', _ca_link) if _ca_link else None %}
{% set ship_addr_doc = frappe.get_doc('Address', doc.shipping_address_name) if doc.get('shipping_address_name') else None %}
{% set _ship_raw = (doc.shipping_address or '').strip() %}
{% set _ship_from_doc = (ship_addr_doc.get_display() or '').strip() if ship_addr_doc else '' %}
{% set shipping_text = _ship_raw or _ship_from_doc or (doc.address_display or '').strip() %}
{% set billing_text = doc.address_display or '' %}
{% set billing_addr_doc = frappe.get_doc('Address', doc.customer_address) if doc.get('customer_address') else None %}
{% set place_supply_display = (billing_addr_doc.get('state') if billing_addr_doc else '') or (doc.get('place_of_supply') or '') %}
{% set _po_gc = frappe.db.sql("SELECT GROUP_CONCAT(DISTINCT purchase_order SEPARATOR ', ') FROM `tabSales Order Item` WHERE parent=%s AND IFNULL(purchase_order,'') != ''", doc.name) %}
{% set po_linked = (_po_gc[0][0] if _po_gc and _po_gc[0] and _po_gc[0][0] else '') %}
{% set po_display = po_linked or (doc.get('inter_company_order_reference') or '') or (doc.po_no or '') %}
{% set site_name_obm = frappe.db.get_value('Offline Buyer Master', doc.custom_offline_buyer_master, 'site_name') if doc.get('custom_offline_buyer_master') else '' %}
{% set company_gst = (doc.get('company_gstin') or '').strip() or ((company.get('gstin') or company.tax_id) if company else '') or '' %}
{% set ns_ca = namespace(lines=[]) %}
{% if company_addr %}{% for line in (company_addr.get_display() or '').splitlines() %}{% if line.strip() %}{% set _ = ns_ca.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% elif doc.get('company_address_display') %}{% for line in (doc.company_address_display or '').splitlines() %}{% if line.strip() %}{% set _ = ns_ca.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% elif company and company.address_html %}{% for line in ((company.address_html or '')|striptags).splitlines() %}{% if line.strip() %}{% set _ = ns_ca.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% endif %}

{% set freebies = doc.custom_marketing_freebies or [] %}
{% set schemes = doc.custom_scheme_item_table or [] %}
{% set total_qty = doc.total_qty or 0 %}

<style>
  @page { size: A4; margin: 10mm; }
  .so-wrap { font-family: Arial, sans-serif; color: #000; font-size: 11px; }
  .so-table { width: 100%; border-collapse: collapse; table-layout: fixed; }
  .so-table td, .so-table th { border: 1px solid #000; padding: 2px 3px; vertical-align: top; line-height: 1.25; word-wrap: break-word; overflow-wrap: break-word; word-break: break-word; }
  .so-table th { font-weight: 700; }
  .so-main-title { font-size: 23px; font-weight: 800; letter-spacing: 0.5px; padding: 5px 3px 7px; }
  .so-header .so-logo { vertical-align: middle; }
  .so-company-address { line-height: 1.22; vertical-align: top; }
  .so-created-by-label { vertical-align: top; white-space: nowrap; width: 1%; }
  .so-created-by-value { vertical-align: top; word-break: break-word; overflow-wrap: anywhere; }
  .center { text-align: center; }
  .left { text-align: left; }
  .right { text-align: right; }
  .bold { font-weight: 700; }
  .small { font-size: 10px; }
  .mt8 { margin-top: 8px; }
  .mt10 { margin-top: 10px; }
  .party-ship-top { vertical-align: top; }
  .party-gst-wrap { padding: 0 !important; vertical-align: top; }
  .so-gst-split { width: 100%; border-collapse: collapse; table-layout: fixed; }
  .so-gst-split td { border: 0; padding: 2px 3px; vertical-align: top; width: 50%; border-right: 1px solid #000; }
  .so-gst-split td:last-child { border-right: 0; }
  table.so-avoid-split { page-break-inside: avoid !important; break-inside: avoid-page !important; }
  .so-table thead { display: table-header-group; }
  .so-table tfoot { display: table-footer-group; }
  .so-table tr { page-break-inside: avoid !important; break-inside: avoid !important; }
  td, th { page-break-inside: avoid !important; break-inside: avoid !important; }
</style>

<div class='so-wrap'>
  <div class='so-main-title center'>SALES ORDER</div>
  <table class='so-table so-header'>
    <colgroup><col style='width:18%'><col style='width:32%'><col style='width:25%'><col style='width:25%'></colgroup>
    <tr>
      <td rowspan='2' class='center bold so-logo' style='width:18%; vertical-align:middle;'>{% if company and company.company_logo %}<img src='{{ frappe.utils.get_url(company.company_logo) }}' alt='' style='max-height:56px; max-width:100%; object-fit:contain;'>{% else %}LOGO{% endif %}</td>
      <td style='width:32%;' class='center'><span class='bold'>{{ company.company_name if company else '' }}</span></td>
      <td style='width:25%;'><span class='bold'>Sales Order #</span><br>{{ doc.name }}</td>
      <td style='width:25%;'><span class='bold'>Sales Date</span><br>{{ frappe.utils.formatdate(doc.transaction_date, 'dd-mm-yyyy') if doc.transaction_date else '' }}</td>
    </tr>
    <tr>
      <td class='center'><span class='bold'>GSTIN: {{ company_gst }}</span></td>
      <td><span class='bold'>Place of Supply</span><br>{{ place_supply_display }}</td>
      <td><span class='bold'>PO#</span><br>{{ po_display }}</td>
    </tr>
    <tr>
      <td colspan='2' class='left so-company-address'><span class='bold'>Company Address</span><br>{% for line in ns_ca.lines %}{{ line }}{% if not loop.last %}<br>{% endif %}{% endfor %}</td>
      <td colspan='2'>&nbsp;</td>
    </tr>
    <tr>
      <td colspan='2' class='center'><span class='bold'>Company Contact</span><br>{% if company and (company.phone_no or company.email) %}<span class='bold'>{{ company.phone_no or '' }}</span>{% if company.phone_no and company.email %} | {% endif %}<span class='bold'>{{ company.email or '' }}</span>{% endif %}</td>
      <td class='left so-created-by-label'><span class='bold'>Created By</span></td>
      <td class='left so-created-by-value'>{{ owner_name }}</td>
    </tr>
    {% if company and company.website %}<tr>
      <td colspan='2' class='center'><span class='bold'>{% set w = company.website.strip().replace('https://','').replace('http://','').rstrip('/') %}{% if not w.lower().startswith('www.') %}www.{% endif %}{{ w }}</span></td>
      <td colspan='2'>&nbsp;</td>
    </tr>{% endif %}
  </table>

  <table class='so-table mt8 so-party'>
    <colgroup><col style='width:50%'><col style='width:50%'></colgroup>
    <tr>
      <td><span class='bold'>Order From:</span></td>
      <td><span class='bold'>Ship To:</span></td>
    </tr>
    <tr>
      <td class='right'>{{ doc.customer_name or doc.customer or '' }} | <span class='bold'>Site Name:</span> {{ site_name_obm or '' }}{% if doc.contact_mobile or doc.contact_email %}<br>{{ doc.contact_mobile or '' }}{% if doc.contact_mobile and doc.contact_email %} | {% endif %}{{ doc.contact_email or '' }}{% endif %}</td>
      <td class='left'><span class='bold'>{{ doc.customer_name or '' }}</span></td>
    </tr>
    <tr>
      <td><span class='bold'>Buyer Billing Address</span><br>{% for line in (billing_text or '').splitlines() %}{{ line }}{% if not loop.last %}<br>{% endif %}{% endfor %}</td>
      <td rowspan='2' class='party-ship-top so-address-plain'><span class='bold'>Buyer Shipping Address</span><br>{% for line in (shipping_text or '').splitlines() %}{{ line }}{% if not loop.last %}<br>{% endif %}{% endfor %}</td>
    </tr>
    <tr>
      <td class='party-gst-wrap'>
        <table class='so-gst-split'>
          <tr>
            <td><span class='bold'>GST Type:</span> {{ 'Registered' if doc.tax_id else 'Unregistered' }}</td>
            <td><span class='bold'>GSTIN:</span> {{ doc.tax_id or '' }}</td>
          </tr>
        </table>
      </td>
    </tr>
  </table>

  <table class='so-table mt8'>
    <thead>
    <tr><th colspan='9' class='center'>ORDER ITEMS</th></tr>
    <tr>
      <th style='width:5%;' class='center'>Sr. No.</th>
      <th style='width:9%;' class='center'>Image</th>
      <th style='width:27%;'>SKU - SKU Name</th>
      <th style='width:8%;' class='center'>QTY</th>
      <th style='width:8%;' class='center'>UOM</th>
      <th style='width:9%;' class='right'>MRP</th>
      <th style='width:9%;' class='right'>Flat Disc %</th>
      <th style='width:9%;' class='right'>Offer Disc %</th>
      <th style='width:16%;' class='right'>Sub Amount</th>
    </tr>
    </thead>
    <tbody>
    {% for row in doc.items %}
    <tr>
      <td class='center'>{{ row.idx }}</td>
      <td class='center'>{% if row.custom_product_image %}<img src='{{ frappe.utils.get_url(row.custom_product_image) }}' alt='' style='height:22px; max-width:100%;'>{% endif %}</td>
      <td>{{ row.item_code or '' }}{% if row.item_name %} - {{ row.item_name }}{% endif %}</td>
      <td class='center'>{{ frappe.utils.fmt_money(row.qty or 0, precision=0).replace('.00','') }}</td>
      <td class='center'>{{ row.uom or '' }}</td>
      <td class='right'>{{ frappe.utils.fmt_money(row.custom_customer_mrp or 0, currency=doc.currency) }}</td>
      <td class='right'>{{ row.custom_flat_discount or 0 }}</td>
      <td class='right'>{{ row.custom_offer or 0 }}</td>
      <td class='right'>{{ frappe.utils.fmt_money(row.amount or 0, currency=doc.currency) }}</td>
    </tr>
    {% endfor %}
    </tbody>
    <tfoot>
    <tr><td colspan='8' class='right bold'>Sub Total</td><td class='right'>{{ frappe.utils.fmt_money(doc.total or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='8' class='right bold'>Cash Dis. (INR)</td><td class='right'>{{ frappe.utils.fmt_money(doc.custom_cash_discount_amount or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='8' class='right bold'>Grand Total</td><td class='right bold'>{{ frappe.utils.fmt_money(doc.grand_total or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='9' class='bold'>Total PCS: {{ frappe.utils.flt(total_qty, 0) }} ({{ doc.items|length if doc.items else 0 }} Items)</td></tr>
    </tfoot>
  </table>

  {% if freebies %}
  <table class='so-table mt10'>
    <thead>
    <tr><th colspan='4' class='center'>Marketing Freebies</th></tr>
    <tr>
      <th style='width:20%;'>SKU</th>
      <th style='width:45%;'>SKU Name</th>
      <th style='width:10%;' class='center'>QTY</th>
      <th style='width:25%;'>Remarks</th>
    </tr>
    </thead>
    <tbody>
    {% for r in freebies %}
    <tr><td>{{ r.item_code or '' }}</td><td>{{ r.item_name or '' }}</td><td class='center'>{{ r.qty or '' }}</td><td>{{ r.remarks or '' }}</td></tr>
    {% endfor %}
    </tbody>
  </table>
  {% endif %}

  {% if schemes %}
  <table class='so-table mt10'>
    <thead>
    <tr><th colspan='4' class='center'>Scheme Details</th></tr>
    <tr>
      <th style='width:20%;'>SKU</th>
      <th style='width:45%;'>SKU Name</th>
      <th style='width:10%;' class='center'>QTY</th>
      <th style='width:25%;'>Scheme</th>
    </tr>
    </thead>
    <tbody>
    {% for r in schemes %}
    <tr><td>{{ r.item_code or '' }}</td><td>{{ r.item_name or '' }}</td><td class='center'>{{ r.qty or '' }}</td><td>{{ r.scheme or '' }}</td></tr>
    {% endfor %}
    </tbody>
  </table>
  {% endif %}

  <table class='so-table mt10 so-avoid-split'>
    <tr><th colspan='2' class='center'>Bank Details</th></tr>
    <tr><td style='width:35%;' class='bold'>Bank Name</td><td>Axis Bank Ltd.</td></tr>
    <tr><td class='bold'>Branch</td><td>Surat</td></tr>
    <tr><td class='bold'>Account Name</td><td>Alpino Health Foods Pvt. Ltd.</td></tr>
    <tr><td class='bold'>Account Number</td><td>919020040914629</td></tr>
    <tr><td class='bold'>IFSC Code</td><td>UTIB0000047</td></tr>
  </table>

  <table class='so-table mt10 so-avoid-split'>
    <tr><td class='center'>Subject to Surat Jurisdiction only.</td></tr>
    <tr><td class='center bold'>Thank you for helping making India Protein Sufficient Nation!</td></tr>
  </table>
</div>
